package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testTrim() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withRecordSeparator("\r\n");
        CSVFormat csvFormatSpy = Mockito.spy(csvFormat);
        CharSequence charSequence = "  test  ";

        // When
        CharSequence result = (CharSequence) CSVFormat.class.getDeclaredMethod("trim", CharSequence.class).invoke(csvFormatSpy, charSequence);

        // Then
        assertEquals("test", result.toString());
    }
}
